{
  "version": 3,
  "sources": ["../src/utils/helpers.ts", "../src/utils/crypto.ts", "../src/savedResponses/storage.ts", "../src/utils/fuzzy.ts", "../src/savedResponses/matcher.ts", "../src/jobQueue/storage.ts", "../src/settings/storage.ts", "../src/autoApply/engine.ts", "../src/autoApply/scraper.ts", "../src/answerBank/index.ts", "../src/background/serviceWorker.ts"],
  "sourcesContent": ["/** Generate a UUID v4 */\nexport function generateId(): string {\n  if (typeof crypto !== 'undefined' && crypto.randomUUID) {\n    return crypto.randomUUID();\n  }\n  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {\n    const r = (Math.random() * 16) | 0;\n    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);\n  });\n}\n\n/** ISO timestamp */\nexport function now(): string {\n  return new Date().toISOString();\n}\n\n/** Redact for logging */\nexport function redact(value: string): string {\n  if (value.length <= 4) return '****';\n  return value.slice(0, 2) + '****' + value.slice(-2);\n}\n\n/** Debounce */\nexport function debounce<T extends (...args: any[]) => void>(fn: T, ms: number): (...args: Parameters<T>) => void {\n  let timer: ReturnType<typeof setTimeout>;\n  return (...args: Parameters<T>) => {\n    clearTimeout(timer);\n    timer = setTimeout(() => fn(...args), ms);\n  };\n}\n\n/** Parse CSV text into rows, handling quoted fields */\nexport function parseCSV(text: string): string[][] {\n  const rows: string[][] = [];\n  let field = '';\n  let inQuotes = false;\n  let row: string[] = [];\n\n  for (let i = 0; i < text.length; i++) {\n    const ch = text[i];\n    const next = text[i + 1];\n\n    if (inQuotes) {\n      if (ch === '\"' && next === '\"') { field += '\"'; i++; }\n      else if (ch === '\"') { inQuotes = false; }\n      else { field += ch; }\n    } else {\n      if (ch === '\"') { inQuotes = true; }\n      else if (ch === ',') { row.push(field.trim()); field = ''; }\n      else if (ch === '\\n' || (ch === '\\r' && next === '\\n')) {\n        row.push(field.trim());\n        if (row.some((c) => c !== '')) rows.push(row);\n        row = []; field = '';\n        if (ch === '\\r') i++;\n      } else { field += ch; }\n    }\n  }\n  row.push(field.trim());\n  if (row.some((c) => c !== '')) rows.push(row);\n  return rows;\n}\n\n/** Validate https URL */\nexport function isValidHttpsUrl(url: string): boolean {\n  try { return new URL(url).protocol === 'https:'; }\n  catch { return false; }\n}\n\n/** Validate http or https URL */\nexport function isValidHttpUrl(url: string): boolean {\n  try {\n    const u = new URL(url);\n    return u.protocol === 'https:' || u.protocol === 'http:';\n  }\n  catch { return false; }\n}\n", "const SALT_LEN = 16;\nconst IV_LEN = 12;\nconst ITERATIONS = 100_000;\n\nasync function deriveKey(pass: string, salt: Uint8Array): Promise<CryptoKey> {\n  const raw = await crypto.subtle.importKey('raw', new TextEncoder().encode(pass), 'PBKDF2', false, ['deriveKey']);\n  return crypto.subtle.deriveKey(\n    { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },\n    raw,\n    { name: 'AES-GCM', length: 256 },\n    false,\n    ['encrypt', 'decrypt']\n  );\n}\n\nexport async function encrypt(data: string, passphrase: string): Promise<string> {\n  const salt = crypto.getRandomValues(new Uint8Array(SALT_LEN));\n  const iv = crypto.getRandomValues(new Uint8Array(IV_LEN));\n  const key = await deriveKey(passphrase, salt);\n  const enc = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, key, new TextEncoder().encode(data));\n  const buf = new Uint8Array(SALT_LEN + IV_LEN + enc.byteLength);\n  buf.set(salt, 0);\n  buf.set(iv, SALT_LEN);\n  buf.set(new Uint8Array(enc), SALT_LEN + IV_LEN);\n  return btoa(String.fromCharCode(...buf));\n}\n\nexport async function decrypt(encoded: string, passphrase: string): Promise<string> {\n  const buf = Uint8Array.from(atob(encoded), (c) => c.charCodeAt(0));\n  const salt = buf.slice(0, SALT_LEN);\n  const iv = buf.slice(SALT_LEN, SALT_LEN + IV_LEN);\n  const ct = buf.slice(SALT_LEN + IV_LEN);\n  const key = await deriveKey(passphrase, salt);\n  const dec = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, key, ct);\n  return new TextDecoder().decode(dec);\n}\n", "import type { SavedResponse, ResponseLibrary, SavedResponsesState } from '../types/index';\nimport { generateId, now } from '../utils/helpers';\nimport { encrypt, decrypt } from '../utils/crypto';\n\nconst KEY = 'ua_saved_responses';\nconst DEFAULT_ID = 'default';\n\nfunction defaultState(): SavedResponsesState {\n  return {\n    libraries: [{\n      id: DEFAULT_ID, name: 'Default', responses: [],\n      createdAt: now(), updatedAt: now(),\n    }],\n    activeLibraryId: DEFAULT_ID,\n    domainMappings: {},\n  };\n}\n\nexport async function loadState(): Promise<SavedResponsesState> {\n  const r = await chrome.storage.local.get(KEY);\n  return (r[KEY] as SavedResponsesState) || defaultState();\n}\n\nexport async function saveState(state: SavedResponsesState): Promise<void> {\n  await chrome.storage.local.set({ [KEY]: state });\n}\n\nexport async function getActiveLibrary(): Promise<ResponseLibrary> {\n  const s = await loadState();\n  return s.libraries.find((l) => l.id === s.activeLibraryId) || s.libraries[0];\n}\n\nexport async function getLibraryForDomain(domain: string): Promise<ResponseLibrary> {\n  const s = await loadState();\n  const mapped = s.domainMappings[domain];\n  if (mapped) { const l = s.libraries.find((x) => x.id === mapped); if (l) return l; }\n  return s.libraries.find((l) => l.id === s.activeLibraryId) || s.libraries[0];\n}\n\nexport async function getLibraries(): Promise<ResponseLibrary[]> {\n  return (await loadState()).libraries;\n}\n\nexport async function setActiveLibrary(id: string): Promise<void> {\n  const s = await loadState();\n  if (s.libraries.some((l) => l.id === id)) { s.activeLibraryId = id; await saveState(s); }\n}\n\nexport async function createLibrary(name: string): Promise<ResponseLibrary> {\n  const s = await loadState();\n  const lib: ResponseLibrary = { id: generateId(), name, responses: [], createdAt: now(), updatedAt: now() };\n  s.libraries.push(lib);\n  await saveState(s);\n  return lib;\n}\n\nexport async function deleteLibrary(id: string): Promise<boolean> {\n  const s = await loadState();\n  if (s.libraries.length <= 1) return false;\n  s.libraries = s.libraries.filter((l) => l.id !== id);\n  for (const [d, lid] of Object.entries(s.domainMappings)) if (lid === id) delete s.domainMappings[d];\n  if (s.activeLibraryId === id) s.activeLibraryId = s.libraries[0].id;\n  await saveState(s);\n  return true;\n}\n\nexport async function setDomainMapping(domain: string, libId: string): Promise<void> {\n  const s = await loadState();\n  s.domainMappings[domain] = libId;\n  await saveState(s);\n}\n\nexport async function removeDomainMapping(domain: string): Promise<void> {\n  const s = await loadState();\n  delete s.domainMappings[domain];\n  await saveState(s);\n}\n\nexport async function getDomainMappings(): Promise<Record<string, string>> {\n  return (await loadState()).domainMappings;\n}\n\n// \u2500\u2500\u2500 CRUD \u2500\u2500\u2500\n\nexport async function getResponses(libId?: string): Promise<SavedResponse[]> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  return s.libraries.find((l) => l.id === id)?.responses || [];\n}\n\nexport async function saveResponse(resp: SavedResponse, libId?: string): Promise<SavedResponse> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) throw new Error('Library not found');\n  const ts = now();\n  const idx = lib.responses.findIndex((r) => r.id === resp.id);\n  if (idx >= 0) { lib.responses[idx] = { ...resp, updatedAt: ts }; }\n  else { lib.responses.push({ ...resp, id: resp.id || generateId(), createdAt: resp.createdAt || ts, updatedAt: ts }); }\n  lib.updatedAt = ts;\n  await saveState(s);\n  return resp;\n}\n\nexport async function deleteResponse(respId: string, libId?: string): Promise<void> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) return;\n  lib.responses = lib.responses.filter((r) => r.id !== respId);\n  lib.updatedAt = now();\n  await saveState(s);\n}\n\nexport async function deleteResponses(ids: string[], libId?: string): Promise<void> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) return;\n  const set = new Set(ids);\n  lib.responses = lib.responses.filter((r) => !set.has(r.id));\n  lib.updatedAt = now();\n  await saveState(s);\n}\n\nexport async function bulkTag(ids: string[], tags: string[], libId?: string): Promise<void> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) return;\n  const set = new Set(ids);\n  for (const r of lib.responses) {\n    if (set.has(r.id)) {\n      const existing = new Set(r.tags || []);\n      for (const t of tags) existing.add(t);\n      r.tags = [...existing];\n      r.updatedAt = now();\n    }\n  }\n  lib.updatedAt = now();\n  await saveState(s);\n}\n\nexport async function mergeResponses(keepId: string, mergeId: string, libId?: string): Promise<void> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) return;\n  const keep = lib.responses.find((r) => r.id === keepId);\n  const merge = lib.responses.find((r) => r.id === mergeId);\n  if (!keep || !merge) return;\n  keep.keywords = [...new Set([...keep.keywords, ...merge.keywords])];\n  keep.appearances += merge.appearances;\n  keep.updatedAt = now();\n  lib.responses = lib.responses.filter((r) => r.id !== mergeId);\n  lib.updatedAt = now();\n  await saveState(s);\n}\n\nexport async function recordUsage(respId: string, libId?: string): Promise<void> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) return;\n  const r = lib.responses.find((x) => x.id === respId);\n  if (r) { r.appearances++; r.lastUsedAt = now(); r.updatedAt = now(); lib.updatedAt = now(); await saveState(s); }\n}\n\n// \u2500\u2500\u2500 Import / Export \u2500\u2500\u2500\n\nexport async function importResponses(data: SavedResponse[], libId?: string, mode: 'merge' | 'replace' = 'merge'): Promise<number> {\n  const s = await loadState();\n  const id = libId || s.activeLibraryId;\n  const lib = s.libraries.find((l) => l.id === id);\n  if (!lib) throw new Error('Library not found');\n  const ts = now();\n  if (mode === 'replace') lib.responses = [];\n  let count = 0;\n  for (const e of data) {\n    const norm: SavedResponse = {\n      id: e.id || generateId(),\n      key: e.key || '',\n      keywords: Array.isArray(e.keywords) ? e.keywords : [],\n      question: e.question || '',\n      response: e.response || '',\n      appearances: typeof e.appearances === 'number' ? e.appearances : 0,\n      fromAutofill: typeof e.fromAutofill === 'boolean' ? e.fromAutofill : false,\n      tags: e.tags, lastUsedAt: e.lastUsedAt, createdAt: e.createdAt || ts,\n      updatedAt: e.updatedAt || ts, domains: e.domains, atsTypes: e.atsTypes,\n    };\n    if (mode === 'merge') {\n      const existing = lib.responses.find((r) => r.id === norm.id || r.question === norm.question);\n      if (existing) {\n        existing.keywords = [...new Set([...existing.keywords, ...norm.keywords])];\n        existing.appearances = Math.max(existing.appearances, norm.appearances);\n        existing.response = norm.response;\n        existing.updatedAt = ts;\n        continue;\n      }\n    }\n    lib.responses.push(norm);\n    count++;\n  }\n  lib.updatedAt = ts;\n  await saveState(s);\n  return count;\n}\n\nexport async function exportResponses(libId?: string): Promise<SavedResponse[]> {\n  const responses = await getResponses(libId);\n  return responses.map((r) => ({\n    appearances: r.appearances,\n    fromAutofill: r.fromAutofill,\n    id: r.id,\n    key: r.key,\n    keywords: r.keywords,\n    question: r.question,\n    response: r.response,\n    ...(r.tags?.length ? { tags: r.tags } : {}),\n    ...(r.lastUsedAt ? { lastUsedAt: r.lastUsedAt } : {}),\n    ...(r.createdAt ? { createdAt: r.createdAt } : {}),\n    ...(r.updatedAt ? { updatedAt: r.updatedAt } : {}),\n    ...(r.domains?.length ? { domains: r.domains } : {}),\n    ...(r.atsTypes?.length ? { atsTypes: r.atsTypes } : {}),\n  }));\n}\n\nexport async function exportEncrypted(passphrase: string, libId?: string): Promise<string> {\n  const data = await exportResponses(libId);\n  return encrypt(JSON.stringify(data, null, 2), passphrase);\n}\n\nexport async function importEncrypted(encoded: string, passphrase: string, libId?: string, mode: 'merge' | 'replace' = 'merge'): Promise<number> {\n  const json = await decrypt(encoded, passphrase);\n  return importResponses(JSON.parse(json), libId, mode);\n}\n\nexport async function searchResponses(query: string, libId?: string): Promise<SavedResponse[]> {\n  const all = await getResponses(libId);\n  if (!query.trim()) return all;\n  const q = query.toLowerCase();\n  return all.filter((r) =>\n    r.question.toLowerCase().includes(q) ||\n    r.response.toLowerCase().includes(q) ||\n    r.key.toLowerCase().includes(q) ||\n    r.keywords.some((k) => k.toLowerCase().includes(q)) ||\n    (r.tags && r.tags.some((t) => t.toLowerCase().includes(q)))\n  );\n}\n", "/** Normalize: lowercase, strip punctuation, collapse whitespace */\nexport function normalize(text: string): string {\n  return text.toLowerCase().replace(/[^\\w\\s]/g, ' ').replace(/\\s+/g, ' ').trim();\n}\n\n/** Tokenize normalized text */\nexport function tokenize(text: string): string[] {\n  return normalize(text).split(' ').filter(Boolean);\n}\n\n/** Levenshtein distance */\nexport function levenshtein(a: string, b: string): number {\n  const m = a.length, n = b.length;\n  if (m === 0) return n;\n  if (n === 0) return m;\n  let prev = Array.from({ length: n + 1 }, (_, i) => i);\n  let curr = new Array<number>(n + 1);\n  for (let i = 1; i <= m; i++) {\n    curr[0] = i;\n    for (let j = 1; j <= n; j++) {\n      curr[j] = Math.min(\n        prev[j] + 1,\n        curr[j - 1] + 1,\n        prev[j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1)\n      );\n    }\n    [prev, curr] = [curr, prev];\n  }\n  return prev[n];\n}\n\n/** Normalized similarity 0\u20131 */\nexport function stringSimilarity(a: string, b: string): number {\n  const na = normalize(a), nb = normalize(b);\n  if (na === nb) return 1;\n  const max = Math.max(na.length, nb.length);\n  return max === 0 ? 1 : 1 - levenshtein(na, nb) / max;\n}\n\n/** Token overlap (Jaccard) */\nexport function tokenOverlap(a: string[], b: string[]): number {\n  if (!a.length && !b.length) return 1;\n  if (!a.length || !b.length) return 0;\n  const sa = new Set(a), sb = new Set(b);\n  let inter = 0;\n  for (const t of sa) if (sb.has(t)) inter++;\n  return inter / new Set([...sa, ...sb]).size;\n}\n\n/** Fuzzy per-token match */\nexport function fuzzyTokenMatch(a: string[], b: string[]): number {\n  if (!a.length) return b.length === 0 ? 1 : 0;\n  let total = 0;\n  for (const ta of a) {\n    let best = 0;\n    for (const tb of b) best = Math.max(best, stringSimilarity(ta, tb));\n    total += best;\n  }\n  return total / a.length;\n}\n\n/** Combined hybrid similarity */\nexport function hybridSimilarity(query: string, target: string, keywords: string[]): number {\n  const qt = tokenize(query), tt = tokenize(target);\n  const direct = stringSimilarity(query, target) * 0.3;\n  const overlap = tokenOverlap(qt, tt) * 0.25;\n  const fuzzy = fuzzyTokenMatch(qt, tt) * 0.25;\n  let kw = 0;\n  if (keywords.length) {\n    const nq = normalize(query);\n    let hit = 0;\n    for (const k of keywords) if (nq.includes(normalize(k))) hit++;\n    kw = (hit / keywords.length) * 0.2;\n  }\n  return direct + overlap + fuzzy + kw;\n}\n\n/** Find near-duplicate pairs above threshold */\nexport function findDuplicates(\n  items: { id: string; question: string }[],\n  threshold = 0.75\n): { idA: string; idB: string; similarity: number }[] {\n  const out: { idA: string; idB: string; similarity: number }[] = [];\n  for (let i = 0; i < items.length; i++) {\n    for (let j = i + 1; j < items.length; j++) {\n      const sim = stringSimilarity(items[i].question, items[j].question);\n      if (sim >= threshold) out.push({ idA: items[i].id, idB: items[j].id, similarity: sim });\n    }\n  }\n  return out.sort((a, b) => b.similarity - a.similarity);\n}\n", "import type { SavedResponse, SuggestionItem, ATSType } from '../types/index';\nimport { hybridSimilarity, normalize, tokenize, tokenOverlap } from '../utils/fuzzy';\n\nexport interface MatchOptions {\n  domain?: string;\n  atsType?: ATSType;\n  maxResults?: number;\n}\n\n/** Score one response against a query string. Returns 0\u20131 and explanation. */\nexport function scoreResponse(\n  query: string,\n  resp: SavedResponse,\n  opts: MatchOptions = {}\n): { score: number; explanation: string } {\n  const parts: string[] = [];\n  let score = 0;\n\n  // 1. Hybrid text similarity vs question (0.45)\n  const qSim = hybridSimilarity(query, resp.question, resp.keywords);\n  score += qSim * 0.45;\n  parts.push(`q_sim=${qSim.toFixed(3)}`);\n\n  // 2. Key overlap (0.20)\n  const keyTokens = resp.key.split('|').filter(Boolean);\n  const qTokens = tokenize(query);\n  const keyOv = tokenOverlap(qTokens, keyTokens);\n  score += keyOv * 0.20;\n  parts.push(`key=${keyOv.toFixed(3)}`);\n\n  // 3. Popularity (0.10)\n  const pop = Math.min(Math.log2(1 + resp.appearances) / 10, 1);\n  score += pop * 0.10;\n  parts.push(`pop=${pop.toFixed(3)}`);\n\n  // 4. Recency (0.10)\n  let rec = 0;\n  if (resp.lastUsedAt) {\n    const days = (Date.now() - new Date(resp.lastUsedAt).getTime()) / 86_400_000;\n    rec = Math.max(0, 1 - days / 90);\n  }\n  score += rec * 0.10;\n  parts.push(`rec=${rec.toFixed(3)}`);\n\n  // 5. Domain / ATS hint (0.10)\n  let ctx = 0;\n  if (opts.domain && resp.domains?.includes(opts.domain)) { ctx += 0.5; parts.push('dom+'); }\n  if (opts.atsType && resp.atsTypes?.includes(opts.atsType)) { ctx += 0.5; parts.push('ats+'); }\n  score += Math.min(ctx, 1) * 0.10;\n\n  // 6. Keyword bonus (0.05)\n  let kwb = 0;\n  if (resp.keywords.length) {\n    const nq = normalize(query);\n    let hit = 0;\n    for (const k of resp.keywords) if (nq.includes(k.toLowerCase())) hit++;\n    kwb = hit / resp.keywords.length;\n  }\n  score += kwb * 0.05;\n  parts.push(`kw=${kwb.toFixed(3)}`);\n\n  return { score: Math.min(score, 1), explanation: parts.join(', ') };\n}\n\n/** Top N matches above threshold */\nexport function findMatches(query: string, responses: SavedResponse[], opts: MatchOptions = {}): SuggestionItem[] {\n  const max = opts.maxResults || 3;\n  if (!query.trim() || !responses.length) return [];\n  return responses\n    .map((r) => { const { score, explanation } = scoreResponse(query, r, opts); return { response: r, score, explanation }; })\n    .filter((s) => s.score > 0.15)\n    .sort((a, b) => b.score - a.score)\n    .slice(0, max);\n}\n\n/** Best single match for autofill (null if below confidence) */\nexport function findBestMatch(query: string, responses: SavedResponse[], opts: MatchOptions = {}): SuggestionItem | null {\n  const m = findMatches(query, responses, { ...opts, maxResults: 1 });\n  return m.length && m[0].score >= 0.3 ? m[0] : null;\n}\n", "import type { JobQueueItem, JobQueueState, JobStatus, CSVImportStats } from '../types/index';\nimport { generateId, now, parseCSV, isValidHttpsUrl } from '../utils/helpers';\n\nconst KEY = 'ua_job_queue';\n\nfunction defaultState(): JobQueueState {\n  return { items: [], currentItemId: null };\n}\n\nexport async function loadQueue(): Promise<JobQueueState> {\n  const r = await chrome.storage.local.get(KEY);\n  return (r[KEY] as JobQueueState) || defaultState();\n}\n\nasync function saveQueue(state: JobQueueState): Promise<void> {\n  await chrome.storage.local.set({ [KEY]: state });\n}\n\nexport async function getItems(): Promise<JobQueueItem[]> {\n  return (await loadQueue()).items;\n}\n\n/** Normalize a URL: trim, lowercase host, remove tracking params, remove trailing slash */\nexport function normalizeUrl(urlStr: string): string {\n  try {\n    const url = new URL(urlStr.trim());\n    url.hostname = url.hostname.toLowerCase();\n    // Remove common tracking parameters\n    const trackingParams = ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'ref', 'fbclid', 'gclid', 'source', 'trackingId'];\n    for (const p of trackingParams) {\n      url.searchParams.delete(p);\n    }\n    // Remove trailing slash\n    let path = url.pathname;\n    if (path.length > 1 && path.endsWith('/')) path = path.slice(0, -1);\n    url.pathname = path;\n    return url.toString();\n  } catch {\n    return urlStr.trim();\n  }\n}\n\n/** Validate a URL is HTTP or HTTPS */\nexport function isValidUrl(url: string): boolean {\n  try {\n    const u = new URL(url);\n    return u.protocol === 'https:' || u.protocol === 'http:';\n  } catch {\n    return false;\n  }\n}\n\nexport async function addUrls(urls: Array<{ url: string; company?: string; role?: string; priority?: number; notes?: string }>): Promise<number> {\n  const s = await loadQueue();\n  const existing = new Set(s.items.map((i) => normalizeUrl(i.url)));\n  let added = 0;\n  for (const u of urls) {\n    const normalized = normalizeUrl(u.url);\n    if (!isValidUrl(normalized) || existing.has(normalized)) continue;\n    existing.add(normalized);\n    s.items.push({\n      id: generateId(),\n      url: u.url.trim(),\n      normalizedUrl: normalized,\n      company: u.company,\n      role: u.role,\n      priority: u.priority,\n      notes: u.notes,\n      status: 'not_started',\n      source: 'manual',\n      retryCount: 0,\n      createdAt: now(),\n      updatedAt: now(),\n    });\n    added++;\n  }\n  await saveQueue(s);\n  return added;\n}\n\nexport async function updateStatus(itemId: string, status: JobStatus, reason?: string): Promise<void> {\n  const s = await loadQueue();\n  const item = s.items.find((i) => i.id === itemId);\n  if (item) {\n    item.status = status;\n    item.updatedAt = now();\n    if (reason) {\n      if (status === 'blocked') item.blockedReason = reason;\n      if (status === 'failed') item.failReason = reason;\n    }\n    if (status === 'applied') item.appliedAt = now();\n    if (status === 'opened' || status === 'applying' || status === 'prefilled') s.currentItemId = itemId;\n    if (status === 'completed' || status === 'blocked' || status === 'applied' || status === 'failed' || status === 'skipped') {\n      if (s.currentItemId === itemId) s.currentItemId = null;\n    }\n    await saveQueue(s);\n  }\n}\n\nexport async function removeItem(itemId: string): Promise<void> {\n  const s = await loadQueue();\n  s.items = s.items.filter((i) => i.id !== itemId);\n  if (s.currentItemId === itemId) s.currentItemId = null;\n  await saveQueue(s);\n}\n\nexport async function clearQueue(): Promise<void> {\n  await saveQueue(defaultState());\n}\n\nexport async function retryFailed(): Promise<number> {\n  const s = await loadQueue();\n  let count = 0;\n  for (const item of s.items) {\n    if (item.status === 'failed' && (item.retryCount || 0) < 3) {\n      item.status = 'not_started';\n      item.retryCount = (item.retryCount || 0) + 1;\n      item.failReason = undefined;\n      item.updatedAt = now();\n      count++;\n    }\n  }\n  await saveQueue(s);\n  return count;\n}\n\nexport async function getNextJob(): Promise<JobQueueItem | null> {\n  const s = await loadQueue();\n  // Priority ordering: higher priority first, then by creation time\n  const pending = s.items\n    .filter((i) => i.status === 'not_started')\n    .sort((a, b) => {\n      const pa = a.priority ?? 0;\n      const pb = b.priority ?? 0;\n      if (pb !== pa) return pb - pa;\n      return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();\n    });\n  return pending[0] || null;\n}\n\nexport async function exportQueue(): Promise<string> {\n  const items = await getItems();\n  const header = 'url,company,role,priority,notes,status,source,applied_at,fail_reason';\n  const rows = items.map((i) =>\n    [i.url, i.company || '', i.role || '', i.priority ?? '', i.notes || '', i.status, i.source || '', i.appliedAt || '', i.failReason || '']\n      .map((v) => `\"${String(v).replace(/\"/g, '\"\"')}\"`)\n      .join(',')\n  );\n  return [header, ...rows].join('\\n');\n}\n\n/** Enhanced CSV parsing with detailed import stats */\nexport function parseJobCSVWithStats(text: string): CSVImportStats {\n  const stats: CSVImportStats = {\n    totalParsed: 0,\n    validUrls: 0,\n    invalidUrls: 0,\n    duplicates: 0,\n    added: 0,\n    invalidRows: [],\n  };\n\n  const rows = parseCSV(text);\n  if (rows.length < 1) return stats;\n\n  // Try to detect header row\n  const firstRow = rows[0].map((h) => h.toLowerCase().trim());\n  let urlIdx = firstRow.findIndex((h) => ['url', 'job_url', 'link', 'job_link', 'application_url'].includes(h));\n  let hasHeader = urlIdx >= 0;\n\n  // If no header found, check if first row is a single-column CSV with a URL\n  if (!hasHeader) {\n    if (rows[0].length === 1 && isValidUrl(rows[0][0].trim())) {\n      urlIdx = 0;\n      hasHeader = false;\n    } else {\n      // Try treating first column as URL column\n      urlIdx = 0;\n      hasHeader = false;\n    }\n  }\n\n  const companyIdx = hasHeader ? firstRow.indexOf('company') : -1;\n  const roleIdx = hasHeader ? firstRow.findIndex((h) => ['role', 'title', 'job_title', 'position'].includes(h)) : -1;\n  const priorityIdx = hasHeader ? firstRow.indexOf('priority') : -1;\n  const notesIdx = hasHeader ? firstRow.indexOf('notes') : -1;\n\n  const seen = new Set<string>();\n  const startRow = hasHeader ? 1 : 0;\n\n  for (let i = startRow; i < rows.length; i++) {\n    const row = rows[i];\n    stats.totalParsed++;\n    const rawUrl = row[urlIdx]?.trim();\n\n    if (!rawUrl) {\n      stats.invalidUrls++;\n      stats.invalidRows.push({ row: i + 1, url: rawUrl || '(empty)', reason: 'Empty URL' });\n      continue;\n    }\n\n    if (!isValidUrl(rawUrl)) {\n      stats.invalidUrls++;\n      stats.invalidRows.push({ row: i + 1, url: rawUrl, reason: 'Invalid URL format' });\n      continue;\n    }\n\n    const normalized = normalizeUrl(rawUrl);\n    if (seen.has(normalized)) {\n      stats.duplicates++;\n      continue;\n    }\n\n    seen.add(normalized);\n    stats.validUrls++;\n  }\n\n  return stats;\n}\n\n/** Parse CSV and extract job URLs with full dedup and validation */\nexport function parseJobCSV(text: string): Array<{ url: string; company?: string; role?: string; priority?: number; notes?: string }> {\n  const rows = parseCSV(text);\n  if (rows.length < 1) return [];\n\n  const firstRow = rows[0].map((h) => h.toLowerCase().trim());\n  let urlIdx = firstRow.findIndex((h) => ['url', 'job_url', 'link', 'job_link', 'application_url'].includes(h));\n  let hasHeader = urlIdx >= 0;\n\n  if (!hasHeader) {\n    urlIdx = 0;\n    hasHeader = false;\n    // Check if first row looks like a header\n    if (firstRow[0] && !isValidUrl(rows[0][0].trim())) {\n      hasHeader = true;\n    }\n  }\n\n  const companyIdx = hasHeader ? firstRow.indexOf('company') : -1;\n  const roleIdx = hasHeader ? firstRow.findIndex((h) => ['role', 'title', 'job_title', 'position'].includes(h)) : -1;\n  const priorityIdx = hasHeader ? firstRow.indexOf('priority') : -1;\n  const notesIdx = hasHeader ? firstRow.indexOf('notes') : -1;\n\n  const results: Array<{ url: string; company?: string; role?: string; priority?: number; notes?: string }> = [];\n  const seen = new Set<string>();\n  const startRow = hasHeader ? 1 : 0;\n\n  for (let i = startRow; i < rows.length; i++) {\n    const row = rows[i];\n    const rawUrl = row[urlIdx]?.trim();\n    if (!rawUrl || !isValidUrl(rawUrl)) continue;\n\n    const normalized = normalizeUrl(rawUrl);\n    if (seen.has(normalized)) continue;\n    seen.add(normalized);\n\n    results.push({\n      url: rawUrl,\n      company: companyIdx >= 0 ? row[companyIdx]?.trim() : undefined,\n      role: roleIdx >= 0 ? row[roleIdx]?.trim() : undefined,\n      priority: priorityIdx >= 0 ? parseInt(row[priorityIdx], 10) || undefined : undefined,\n      notes: notesIdx >= 0 ? row[notesIdx]?.trim() : undefined,\n    });\n  }\n  return results;\n}\n\n/** Import CSV jobs with source tracking */\nexport async function importCSVJobs(text: string): Promise<CSVImportStats> {\n  const stats = parseJobCSVWithStats(text);\n  const parsed = parseJobCSV(text);\n\n  const s = await loadQueue();\n  const existing = new Set(s.items.map((i) => normalizeUrl(i.url)));\n  let added = 0;\n\n  for (const u of parsed) {\n    const normalized = normalizeUrl(u.url);\n    if (existing.has(normalized)) {\n      stats.duplicates++;\n      continue;\n    }\n    existing.add(normalized);\n    s.items.push({\n      id: generateId(),\n      url: u.url.trim(),\n      normalizedUrl: normalized,\n      company: u.company,\n      role: u.role,\n      priority: u.priority,\n      notes: u.notes,\n      status: 'not_started',\n      source: 'csv_import',\n      retryCount: 0,\n      createdAt: now(),\n      updatedAt: now(),\n    });\n    added++;\n  }\n\n  await saveQueue(s);\n  stats.added = added;\n  return stats;\n}\n\n/** Get imported jobs only (from CSV) */\nexport async function getImportedJobs(): Promise<JobQueueItem[]> {\n  const s = await loadQueue();\n  return s.items.filter((i) => i.source === 'csv_import');\n}\n\n/** Get import pipeline stats */\nexport async function getImportStats(): Promise<{\n  total: number; pending: number; applying: number; applied: number;\n  failed: number; skipped: number; completed: number;\n}> {\n  const items = await getImportedJobs();\n  return {\n    total: items.length,\n    pending: items.filter((i) => i.status === 'not_started').length,\n    applying: items.filter((i) => i.status === 'applying' || i.status === 'opened' || i.status === 'prefilled').length,\n    applied: items.filter((i) => i.status === 'applied').length,\n    failed: items.filter((i) => i.status === 'failed').length,\n    skipped: items.filter((i) => i.status === 'skipped').length,\n    completed: items.filter((i) => i.status === 'completed').length,\n  };\n}\n", "/**\n * Extension settings storage.\n * Handles all global settings including auto-apply, scraper, and credentials.\n */\n\nimport type { ExtensionSettings, AutoApplySettings, ScraperSettings, TailoringSettings, ApplicationsAccount } from '../types/index';\nimport { encrypt, decrypt } from '../utils/crypto';\n\nconst KEY = 'ua_settings';\n\nfunction defaultAutoApply(): AutoApplySettings {\n  return {\n    enabled: true,\n    autoSubmit: false,           // Default OFF for safety\n    autoSubmitPerSite: {},\n    maxConcurrency: 1,\n    delayBetweenJobs: 3000,      // 3 seconds between jobs\n    humanLikePacing: true,\n    closeTabAfterApply: false,\n    retryFailedMax: 2,\n    requireResumeForSubmit: true,\n    domainAllowlist: [\n      'myworkdayjobs.com', 'myworkday.com', 'greenhouse.io', 'lever.co',\n      'smartrecruiters.com', 'icims.com', 'taleo.net', 'ashbyhq.com',\n      'bamboohr.com', 'oraclecloud.com', 'indeed.com', 'linkedin.com',\n    ],\n    rateLimit: { maxPerHour: 30, maxPerDay: 200 },\n    paused: false,\n  };\n}\n\nfunction defaultScraper(): ScraperSettings {\n  return {\n    enabled: false,\n    intervalMinutes: 10,\n    sources: { ats: true, indeed: true, linkedinNonEasyApply: true },\n    targetCountPerSession: 50,\n    freshnessTiers: { tierA: 30, tierB: 1440, tierC: 4320 },\n    filters: {\n      keywords: [],\n      geoRadius: 50,\n      location: '',\n      seniority: [],\n      remoteOnly: false,\n      hybridAllowed: true,\n    },\n  };\n}\n\nfunction defaultTailoring(): TailoringSettings {\n  return {\n    enabled: true,\n    intensity: 0.8,               // High tailoring by default\n    profileKeywords: [],\n    targetKeywords: [],\n    profileSummary: '',\n  };\n}\n\nfunction defaultSettings(): ExtensionSettings {\n  return {\n    autoApply: defaultAutoApply(),\n    scraper: defaultScraper(),\n    tailoring: defaultTailoring(),\n    applicationsAccount: null,\n    creditsUnlimited: true,      // Unlimited credits by default\n    autoDetectAndFill: true,     // Auto-detect ATS and fill on page load\n    universalFormDetection: true, // Detect ALL forms, not just known ATS\n    supportedPlatforms: {\n      workday: true, greenhouse: true, lever: true, smartrecruiters: true,\n      icims: true, taleo: true, ashby: true, bamboohr: true,\n      oraclecloud: true, linkedin: true, indeed: true, companysite: true,\n    },\n  };\n}\n\nexport async function loadSettings(): Promise<ExtensionSettings> {\n  const r = await chrome.storage.local.get(KEY);\n  const saved = r[KEY] as ExtensionSettings | undefined;\n  if (!saved) return defaultSettings();\n  // Merge with defaults to handle newly added fields\n  const defaults = defaultSettings();\n  return {\n    ...defaults,\n    ...saved,\n    autoApply: { ...defaults.autoApply, ...saved.autoApply },\n    scraper: { ...defaults.scraper, ...saved.scraper, filters: { ...defaults.scraper.filters, ...(saved.scraper?.filters || {}) } },\n    tailoring: { ...defaults.tailoring, ...(saved.tailoring || {}) },\n    supportedPlatforms: { ...defaults.supportedPlatforms, ...saved.supportedPlatforms },\n  };\n}\n\nexport async function saveSettings(settings: ExtensionSettings): Promise<void> {\n  await chrome.storage.local.set({ [KEY]: settings });\n}\n\nexport async function updateAutoApply(update: Partial<AutoApplySettings>): Promise<void> {\n  const s = await loadSettings();\n  s.autoApply = { ...s.autoApply, ...update };\n  await saveSettings(s);\n}\n\nexport async function updateScraper(update: Partial<ScraperSettings>): Promise<void> {\n  const s = await loadSettings();\n  s.scraper = { ...s.scraper, ...update };\n  await saveSettings(s);\n}\n\n/**\n * Save applications account credentials.\n * Password is encrypted with a user-provided passphrase using AES-GCM.\n * The passphrase is NEVER stored - user must provide it each session.\n */\nexport async function saveAppAccount(email: string, password: string, passphrase: string): Promise<void> {\n  const s = await loadSettings();\n  const encryptedPassword = await encrypt(password, passphrase);\n  s.applicationsAccount = {\n    email,\n    encryptedPassword,\n    salt: crypto.getRandomValues(new Uint8Array(16)).toString(),\n  };\n  await saveSettings(s);\n}\n\n/**\n * Get decrypted application account credentials.\n * Requires the user's passphrase to decrypt.\n */\nexport async function getAppAccount(passphrase: string): Promise<{ email: string; password: string } | null> {\n  const s = await loadSettings();\n  if (!s.applicationsAccount) return null;\n  try {\n    const password = await decrypt(s.applicationsAccount.encryptedPassword, passphrase);\n    return { email: s.applicationsAccount.email, password };\n  } catch {\n    return null; // Wrong passphrase\n  }\n}\n\nexport async function clearAppAccount(): Promise<void> {\n  const s = await loadSettings();\n  s.applicationsAccount = null;\n  await saveSettings(s);\n}\n\nexport async function getAppAccountEmail(): Promise<string | null> {\n  const s = await loadSettings();\n  return s.applicationsAccount?.email || null;\n}\n\n/** Check if credits are unlimited (always true in this implementation) */\nexport async function checkCredits(): Promise<{ unlimited: boolean; remaining: number }> {\n  const s = await loadSettings();\n  return { unlimited: s.creditsUnlimited, remaining: Infinity };\n}\n", "/**\n * Auto-Apply Engine\n * Orchestrates the fully automatic job application pipeline.\n * Opens job URLs, detects ATS, runs autofill, optionally submits, closes tabs.\n * Now includes multi-page support, success detection, and Workday automation.\n */\n\nimport type { AutoApplyStatus, AutoApplySettings, JobQueueItem, JobStatus } from '../types/index';\nimport * as queue from '../jobQueue/storage';\nimport { loadSettings } from '../settings/storage';\n\nlet _status: AutoApplyStatus = {\n  running: false,\n  paused: false,\n  currentJobId: null,\n  currentJobUrl: null,\n  totalJobs: 0,\n  completedJobs: 0,\n  failedJobs: 0,\n  skippedJobs: 0,\n  startedAt: null,\n  estimatedRemaining: 0,\n};\n\nlet _abortController: AbortController | null = null;\nlet _appliedThisHour = 0;\nlet _appliedToday = 0;\n\n// Rate limiting counters\nconst RATE_KEY = 'ua_rate_limits';\n\nasync function loadRateLimits(): Promise<{ hour: number; day: number; hourReset: number; dayReset: number }> {\n  const r = await chrome.storage.local.get(RATE_KEY);\n  const data = r[RATE_KEY] as any;\n  if (!data) return { hour: 0, day: 0, hourReset: Date.now() + 3600000, dayReset: Date.now() + 86400000 };\n  // Reset if expired\n  const now = Date.now();\n  if (now > data.hourReset) data.hour = 0;\n  if (now > data.dayReset) data.day = 0;\n  return data;\n}\n\nasync function incrementRateLimit(): Promise<void> {\n  const limits = await loadRateLimits();\n  limits.hour++;\n  limits.day++;\n  if (limits.hourReset < Date.now()) limits.hourReset = Date.now() + 3600000;\n  if (limits.dayReset < Date.now()) limits.dayReset = Date.now() + 86400000;\n  await chrome.storage.local.set({ [RATE_KEY]: limits });\n  _appliedThisHour = limits.hour;\n  _appliedToday = limits.day;\n}\n\nasync function checkRateLimit(settings: AutoApplySettings): Promise<boolean> {\n  const limits = await loadRateLimits();\n  _appliedThisHour = limits.hour;\n  _appliedToday = limits.day;\n  return limits.hour < settings.rateLimit.maxPerHour && limits.day < settings.rateLimit.maxPerDay;\n}\n\nexport function getStatus(): AutoApplyStatus {\n  return { ..._status };\n}\n\nfunction delay(ms: number): Promise<void> {\n  return new Promise((resolve) => setTimeout(resolve, ms));\n}\n\n/** Add human-like randomized delay */\nfunction humanDelay(baseMs: number): Promise<void> {\n  const variance = baseMs * 0.3; // 30% variance\n  const actual = baseMs + (Math.random() * variance * 2 - variance);\n  return delay(Math.max(500, actual));\n}\n\n/**\n * Start the auto-apply pipeline.\n * Processes jobs from the queue one at a time:\n * 1. Get next pending job\n * 2. Open URL in a new tab\n * 3. Wait for page load\n * 4. Send START_AUTOFILL to the content script\n * 5. Wait for autofill completion (with multi-page support)\n * 6. Detect success or needs_input\n * 7. Update job status\n * 8. Close tab (if setting enabled)\n * 9. Wait for rate limit delay\n * 10. Repeat\n */\nexport async function startAutoApply(source?: 'all' | 'imported'): Promise<void> {\n  if (_status.running) return;\n\n  const settings = await loadSettings();\n  if (!settings.autoApply.enabled) return;\n\n  _abortController = new AbortController();\n  const items = await queue.getItems();\n  const pendingJobs = items.filter((j) => {\n    if (j.status !== 'not_started') return false;\n    if (source === 'imported' && j.source !== 'csv_import') return false;\n    return true;\n  });\n\n  _status = {\n    running: true,\n    paused: false,\n    currentJobId: null,\n    currentJobUrl: null,\n    totalJobs: pendingJobs.length,\n    completedJobs: 0,\n    failedJobs: 0,\n    skippedJobs: 0,\n    startedAt: new Date().toISOString(),\n    estimatedRemaining: pendingJobs.length,\n  };\n\n  try {\n    await processQueue(settings.autoApply, source);\n  } finally {\n    _status.running = false;\n    _status.currentJobId = null;\n    _status.currentJobUrl = null;\n    _abortController = null;\n  }\n}\n\nasync function processQueue(settings: AutoApplySettings, source?: 'all' | 'imported'): Promise<void> {\n  while (_status.running && !_abortController?.signal.aborted) {\n    if (_status.paused) {\n      await delay(1000);\n      continue;\n    }\n\n    // Check rate limits\n    const withinLimits = await checkRateLimit(settings);\n    if (!withinLimits) {\n      console.log('[UA] Rate limit reached, pausing auto-apply');\n      _status.paused = true;\n      // Auto-resume after rate limit window\n      await delay(60000); // Wait 1 minute then recheck\n      _status.paused = false;\n      continue;\n    }\n\n    // Get next job\n    const job = await queue.getNextJob();\n    if (!job) {\n      console.log('[UA] No more jobs in queue');\n      break;\n    }\n\n    // Filter by source if specified\n    if (source === 'imported' && job.source !== 'csv_import') {\n      continue;\n    }\n\n    // Check if domain is allowed\n    try {\n      const domain = new URL(job.url).hostname;\n      const isAllowed = settings.domainAllowlist.length === 0 ||\n        settings.domainAllowlist.some((d) => domain.includes(d));\n      if (!isAllowed) {\n        await queue.updateStatus(job.id, 'skipped', 'Domain not in allowlist');\n        _status.skippedJobs++;\n        _status.estimatedRemaining--;\n        continue;\n      }\n    } catch {\n      await queue.updateStatus(job.id, 'failed', 'Invalid URL');\n      _status.failedJobs++;\n      _status.estimatedRemaining--;\n      continue;\n    }\n\n    _status.currentJobId = job.id;\n    _status.currentJobUrl = job.url;\n\n    try {\n      await processJob(job, settings);\n      _status.completedJobs++;\n      await incrementRateLimit();\n    } catch (err) {\n      console.error('[UA] Job failed:', job.url, err);\n      // Retry logic\n      const retryCount = (job.retryCount || 0) + 1;\n      if (retryCount <= settings.retryFailedMax) {\n        await queue.updateStatus(job.id, 'not_started', `Retry ${retryCount}/${settings.retryFailedMax}: ${String(err)}`);\n        // Update retry count\n        const items = await queue.getItems();\n        const item = items.find((i) => i.id === job.id);\n        if (item) {\n          item.retryCount = retryCount;\n          const state = await queue.loadQueue();\n          const stateItem = state.items.find((i) => i.id === job.id);\n          if (stateItem) stateItem.retryCount = retryCount;\n          await chrome.storage.local.set({ ua_job_queue: state });\n        }\n      } else {\n        await queue.updateStatus(job.id, 'failed', String(err));\n        _status.failedJobs++;\n      }\n    }\n\n    _status.estimatedRemaining--;\n\n    // Human-like pacing between jobs\n    if (settings.humanLikePacing) {\n      await humanDelay(settings.delayBetweenJobs);\n    } else {\n      await delay(settings.delayBetweenJobs);\n    }\n  }\n}\n\nasync function processJob(job: JobQueueItem, settings: AutoApplySettings): Promise<void> {\n  // Update status to applying\n  await queue.updateStatus(job.id, 'applying');\n\n  // Open the job URL in a new tab\n  const tab = await chrome.tabs.create({ url: job.url, active: false });\n  if (!tab.id) throw new Error('Failed to create tab');\n\n  // Wait for page to load\n  await waitForTabLoad(tab.id, 30000);\n\n  // Small delay for dynamic content to render\n  await delay(2000);\n\n  // Send autofill command to the content script\n  try {\n    await chrome.tabs.sendMessage(tab.id, {\n      type: 'START_AUTOFILL',\n      payload: { autoSubmit: settings.autoSubmit, jobId: job.id },\n    });\n  } catch {\n    // Content script might not be loaded, try injecting it\n    try {\n      await chrome.scripting.executeScript({\n        target: { tabId: tab.id },\n        files: ['content.js'],\n      });\n      await delay(1000);\n      await chrome.tabs.sendMessage(tab.id, {\n        type: 'START_AUTOFILL',\n        payload: { autoSubmit: settings.autoSubmit, jobId: job.id },\n      });\n    } catch (e) {\n      throw new Error(`Cannot inject content script: ${e}`);\n    }\n  }\n\n  // Wait for autofill to complete (with extended timeout for multi-page)\n  const result = await waitForAutofillComplete(tab.id, job.id, 120000);\n\n  if (result === 'applied') {\n    await queue.updateStatus(job.id, 'applied');\n  } else if (result === 'prefilled') {\n    await queue.updateStatus(job.id, 'prefilled');\n  } else if (result === 'needs_input') {\n    await queue.updateStatus(job.id, 'needs_input', 'Manual input required');\n  } else {\n    await queue.updateStatus(job.id, 'prefilled');\n  }\n\n  // Close tab if setting enabled and job was submitted\n  if (settings.closeTabAfterApply && (result === 'applied' || result === 'completed')) {\n    try { await chrome.tabs.remove(tab.id); } catch {}\n  }\n}\n\nfunction waitForTabLoad(tabId: number, timeout: number): Promise<void> {\n  return new Promise((resolve, reject) => {\n    const timer = setTimeout(() => {\n      chrome.tabs.onUpdated.removeListener(listener);\n      resolve(); // Don't reject on timeout, just continue\n    }, timeout);\n\n    function listener(id: number, info: chrome.tabs.TabChangeInfo) {\n      if (id === tabId && info.status === 'complete') {\n        clearTimeout(timer);\n        chrome.tabs.onUpdated.removeListener(listener);\n        resolve();\n      }\n    }\n\n    chrome.tabs.onUpdated.addListener(listener);\n  });\n}\n\nfunction waitForAutofillComplete(tabId: number, jobId: string, timeout: number): Promise<string> {\n  return new Promise((resolve) => {\n    const timer = setTimeout(() => {\n      chrome.runtime.onMessage.removeListener(listener);\n      resolve('prefilled'); // Default to prefilled on timeout\n    }, timeout);\n\n    function listener(msg: any, sender: chrome.runtime.MessageSender) {\n      if (sender.tab?.id === tabId && msg.type === 'PAGE_AUTOFILL_COMPLETE') {\n        clearTimeout(timer);\n        chrome.runtime.onMessage.removeListener(listener);\n        resolve(msg.payload?.status || 'prefilled');\n      }\n    }\n\n    chrome.runtime.onMessage.addListener(listener);\n  });\n}\n\nexport function stopAutoApply(): void {\n  _status.running = false;\n  _abortController?.abort();\n}\n\nexport function pauseAutoApply(): void {\n  _status.paused = true;\n}\n\nexport function resumeAutoApply(): void {\n  _status.paused = false;\n}\n\nexport async function retryFailedJobs(): Promise<number> {\n  return queue.retryFailed();\n}\n", "/**\n * Fresh Jobs Scraper / Scheduler\n *\n * Discovers new job postings and ranks by freshness.\n * Tier A: posted in last 30 minutes\n * Tier B: posted in last 24 hours\n * Tier C: posted in last 3 days\n * Older jobs only included if results < target_count.\n *\n * IMPORTANT COMPLIANCE NOTE:\n * - Indeed and LinkedIn scraping may violate their Terms of Service.\n * - This implementation uses on-device parsing of user-provided search result URLs.\n * - For production use, prefer official APIs/feeds/partner integrations.\n * - The scraper only processes pages the user has already loaded in their browser.\n */\n\nimport type { ScrapedJob, ScraperSettings } from '../types/index';\nimport { generateId } from '../utils/helpers';\nimport { loadSettings, saveSettings } from '../settings/storage';\n\nconst SCRAPED_KEY = 'ua_scraped_jobs';\nlet _scraperInterval: ReturnType<typeof setInterval> | null = null;\nlet _running = false;\n\n/** Get freshness tier based on age in minutes */\nfunction getFreshnessTier(ageMinutes: number, tiers: ScraperSettings['freshnessTiers']): 'A' | 'B' | 'C' | 'old' {\n  if (ageMinutes <= tiers.tierA) return 'A';\n  if (ageMinutes <= tiers.tierB) return 'B';\n  if (ageMinutes <= tiers.tierC) return 'C';\n  return 'old';\n}\n\n/** Load scraped jobs from storage */\nexport async function loadScrapedJobs(): Promise<ScrapedJob[]> {\n  const r = await chrome.storage.local.get(SCRAPED_KEY);\n  return (r[SCRAPED_KEY] as ScrapedJob[]) || [];\n}\n\n/** Save scraped jobs to storage */\nasync function saveScrapedJobs(jobs: ScrapedJob[]): Promise<void> {\n  await chrome.storage.local.set({ [SCRAPED_KEY]: jobs });\n}\n\n/** Add new scraped jobs with deduplication */\nexport async function addScrapedJobs(newJobs: Omit<ScrapedJob, 'id' | 'freshnessTier' | 'status'>[]): Promise<number> {\n  const settings = await loadSettings();\n  const existing = await loadScrapedJobs();\n  const existingUrls = new Set(existing.map((j) => j.url));\n  let added = 0;\n\n  for (const job of newJobs) {\n    if (existingUrls.has(job.url)) continue;\n    existingUrls.add(job.url);\n\n    const firstSeen = new Date(job.firstSeenAt);\n    const ageMinutes = (Date.now() - firstSeen.getTime()) / 60000;\n    const tier = getFreshnessTier(ageMinutes, settings.scraper.freshnessTiers);\n\n    existing.push({\n      id: generateId(),\n      ...job,\n      freshnessTier: tier,\n      status: 'new',\n    });\n    added++;\n  }\n\n  await saveScrapedJobs(existing);\n  return added;\n}\n\n/** Get ranked jobs (freshest first, respecting target count) */\nexport async function getRankedJobs(targetCount?: number): Promise<ScrapedJob[]> {\n  const settings = await loadSettings();\n  const target = targetCount || settings.scraper.targetCountPerSession;\n  const jobs = await loadScrapedJobs();\n\n  // Update freshness tiers based on current time\n  const now = Date.now();\n  for (const job of jobs) {\n    const firstSeen = new Date(job.firstSeenAt);\n    const ageMinutes = (now - firstSeen.getTime()) / 60000;\n    job.freshnessTier = getFreshnessTier(ageMinutes, settings.scraper.freshnessTiers);\n  }\n\n  // Sort: Tier A first, then B, then C, then old\n  // Within each tier, newest first\n  const tierOrder: Record<string, number> = { A: 0, B: 1, C: 2, old: 3 };\n  const sorted = jobs\n    .filter((j) => j.status === 'new')\n    .sort((a, b) => {\n      const tierDiff = tierOrder[a.freshnessTier] - tierOrder[b.freshnessTier];\n      if (tierDiff !== 0) return tierDiff;\n      return new Date(b.firstSeenAt).getTime() - new Date(a.firstSeenAt).getTime();\n    });\n\n  // Return up to target count, preferring fresh jobs\n  const result: ScrapedJob[] = [];\n  for (const job of sorted) {\n    if (result.length >= target) {\n      // Only include older jobs if we haven't hit target\n      if (job.freshnessTier === 'old') break;\n    }\n    result.push(job);\n  }\n\n  return result.slice(0, target);\n}\n\n/**\n * Parse job listings from a page the user has loaded.\n * This runs as a content script on Indeed/LinkedIn search result pages.\n */\nexport function parseIndeedListings(doc: Document): Array<Omit<ScrapedJob, 'id' | 'freshnessTier' | 'status'>> {\n  const jobs: Array<Omit<ScrapedJob, 'id' | 'freshnessTier' | 'status'>> = [];\n  const cards = doc.querySelectorAll('.job_seen_beacon, .jobsearch-ResultsList .result, [data-jk]');\n\n  for (const card of cards) {\n    const linkEl = card.querySelector('a[href*=\"/viewjob\"], a[data-jk], h2 a') as HTMLAnchorElement;\n    if (!linkEl?.href) continue;\n\n    const title = card.querySelector('.jobTitle, [data-testid=\"jobTitle\"], h2')?.textContent?.trim();\n    const company = card.querySelector('.companyName, [data-testid=\"company-name\"]')?.textContent?.trim();\n    const location = card.querySelector('.companyLocation, [data-testid=\"text-location\"]')?.textContent?.trim();\n\n    // Try to get posted date\n    const dateEl = card.querySelector('.date, [data-testid=\"myJobsStateDate\"], .new');\n    let postedAt: string | undefined;\n    if (dateEl?.textContent) {\n      const text = dateEl.textContent.trim().toLowerCase();\n      if (text.includes('just posted') || text.includes('today')) {\n        postedAt = new Date().toISOString();\n      } else {\n        const daysMatch = text.match(/(\\d+)\\s*day/);\n        if (daysMatch) {\n          const d = new Date();\n          d.setDate(d.getDate() - parseInt(daysMatch[1]));\n          postedAt = d.toISOString();\n        }\n      }\n    }\n\n    jobs.push({\n      url: linkEl.href,\n      title,\n      company,\n      location,\n      postedAt,\n      firstSeenAt: new Date().toISOString(),\n      source: 'indeed',\n    });\n  }\n\n  return jobs;\n}\n\nexport function parseLinkedInListings(doc: Document): Array<Omit<ScrapedJob, 'id' | 'freshnessTier' | 'status'>> {\n  const jobs: Array<Omit<ScrapedJob, 'id' | 'freshnessTier' | 'status'>> = [];\n  const cards = doc.querySelectorAll('.jobs-search-results__list-item, [data-job-id], .job-card-container');\n\n  for (const card of cards) {\n    const linkEl = card.querySelector('a[href*=\"/jobs/view/\"]') as HTMLAnchorElement;\n    if (!linkEl?.href) continue;\n\n    // Check if it's Easy Apply - skip if so\n    const easyApply = card.querySelector('[class*=\"easy-apply\"]') ||\n      card.querySelector('.job-card-container__apply-method--easy-apply');\n    if (easyApply) {\n      continue; // Skip Easy Apply jobs\n    }\n\n    const title = card.querySelector('.job-card-list__title, .base-search-card__title')?.textContent?.trim();\n    const company = card.querySelector('.job-card-container__primary-description, .base-search-card__subtitle')?.textContent?.trim();\n    const location = card.querySelector('.job-card-container__metadata-item, .job-search-card__location')?.textContent?.trim();\n\n    const timeEl = card.querySelector('time');\n    const postedAt = timeEl?.getAttribute('datetime') || undefined;\n\n    jobs.push({\n      url: linkEl.href,\n      title,\n      company,\n      location,\n      postedAt,\n      firstSeenAt: new Date().toISOString(),\n      source: 'linkedin',\n      isEasyApply: false,\n    });\n  }\n\n  return jobs;\n}\n\n/** Start the scraper scheduler */\nexport async function startScraper(): Promise<void> {\n  if (_running) return;\n  _running = true;\n\n  const settings = await loadSettings();\n  if (!settings.scraper.enabled) {\n    _running = false;\n    return;\n  }\n\n  const intervalMs = settings.scraper.intervalMinutes * 60 * 1000;\n  _scraperInterval = setInterval(async () => {\n    if (!_running) return;\n    // The actual scraping happens via content scripts on pages the user loads\n    // This interval just updates freshness tiers\n    const jobs = await loadScrapedJobs();\n    const now = Date.now();\n    for (const job of jobs) {\n      const firstSeen = new Date(job.firstSeenAt);\n      const ageMinutes = (now - firstSeen.getTime()) / 60000;\n      job.freshnessTier = getFreshnessTier(ageMinutes, settings.scraper.freshnessTiers);\n    }\n    await saveScrapedJobs(jobs);\n  }, intervalMs);\n}\n\n/** Stop the scraper scheduler */\nexport function stopScraper(): void {\n  _running = false;\n  if (_scraperInterval) {\n    clearInterval(_scraperInterval);\n    _scraperInterval = null;\n  }\n}\n\nexport function isScraperRunning(): boolean {\n  return _running;\n}\n", "/**\n * Answer Bank / Learning System\n * Stores answers keyed by normalized field label for future reuse.\n * Learns from filled forms and provides answers for unfamiliar fields.\n */\n\nconst ANSWER_BANK_KEY = 'ua_answer_bank';\nconst PROFILE_KEY = 'ua_user_profile';\n\nexport interface UserProfile {\n  first_name?: string;\n  last_name?: string;\n  middle_name?: string;\n  preferred_name?: string;\n  email?: string;\n  phone?: string;\n  city?: string;\n  state?: string;\n  postal_code?: string;\n  country?: string;\n  address?: string;\n  linkedin?: string;\n  github?: string;\n  website?: string;\n  twitter?: string;\n  school?: string;\n  degree?: string;\n  major?: string;\n  gpa?: string;\n  graduation_year?: string;\n  current_title?: string;\n  current_company?: string;\n  expected_salary?: string;\n  cover_letter?: string;\n  summary?: string;\n  languages?: string;\n  certifications?: string;\n  nationality?: string;\n  [key: string]: string | undefined;\n}\n\nlet _answerBank: Record<string, string> = {};\nlet _loaded = false;\n\nexport function normalizeKey(s: string): string {\n  return (s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/\\s+/g, ' ').trim();\n}\n\nexport async function loadAnswerBank(): Promise<Record<string, string>> {\n  if (_loaded) return _answerBank;\n  const r = await chrome.storage.local.get(ANSWER_BANK_KEY);\n  _answerBank = r[ANSWER_BANK_KEY] || {};\n  _loaded = true;\n  return _answerBank;\n}\n\nexport async function learnAnswer(label: string, value: string): Promise<void> {\n  if (!label || !value) return;\n  const key = normalizeKey(label);\n  if (!key) return;\n  _answerBank[key] = value;\n  await chrome.storage.local.set({ [ANSWER_BANK_KEY]: _answerBank });\n}\n\nexport function getLearnedAnswer(label: string, el?: HTMLElement): string {\n  const candidates = [\n    label,\n    el?.getAttribute('name') || '',\n    el?.id || '',\n    (el as HTMLInputElement)?.placeholder || '',\n    el?.getAttribute('aria-label') || '',\n  ].filter(Boolean);\n\n  // Exact match\n  for (const c of candidates) {\n    const k = normalizeKey(c);\n    if (_answerBank[k]) return _answerBank[k];\n  }\n\n  // Partial match\n  for (const c of candidates) {\n    const k = normalizeKey(c);\n    if (!k) continue;\n    for (const [bk, bv] of Object.entries(_answerBank)) {\n      if (k.includes(bk) || bk.includes(k)) return bv;\n    }\n  }\n\n  return '';\n}\n\n/**\n * Capture all filled field values from the current page into the answer bank.\n */\nexport async function learnFromPage(doc: Document): Promise<number> {\n  await loadAnswerBank();\n\n  const selector = 'input:not([type=\"hidden\"]):not([type=\"file\"]):not([type=\"submit\"]):not([type=\"button\"]),textarea,select';\n  const elements = doc.querySelectorAll<HTMLElement>(selector);\n  let learned = 0;\n\n  for (const el of elements) {\n    if (!isVisible(el)) continue;\n    if (!hasFieldValue(el)) continue;\n\n    const lbl = getFieldLabel(el);\n    if (!lbl) continue;\n\n    let val: string;\n    if (el instanceof HTMLSelectElement) {\n      val = (el.options[el.selectedIndex]?.textContent || el.value || '').trim();\n    } else {\n      val = ((el as HTMLInputElement).value || '').trim();\n    }\n\n    if (val) {\n      await learnAnswer(lbl, val);\n      learned++;\n    }\n  }\n\n  return learned;\n}\n\nexport async function loadProfile(): Promise<UserProfile> {\n  const r = await chrome.storage.local.get(PROFILE_KEY);\n  return r[PROFILE_KEY] || {};\n}\n\nexport async function saveProfile(profile: UserProfile): Promise<void> {\n  await chrome.storage.local.set({ [PROFILE_KEY]: profile });\n}\n\n// \u2500\u2500\u2500 Helpers \u2500\u2500\u2500\n\nfunction isVisible(el: HTMLElement): boolean {\n  if (!el) return false;\n  const r = el.getBoundingClientRect();\n  return r.width > 0 && r.height > 0 && el.offsetParent !== null;\n}\n\nfunction hasFieldValue(el: HTMLElement): boolean {\n  if (el instanceof HTMLSelectElement) {\n    const val = (el.value || '').trim();\n    if (!val) return false;\n    const idx = el.selectedIndex;\n    if (idx >= 0) {\n      const txt = (el.options[idx]?.textContent || '').trim().toLowerCase();\n      if (!txt || /^(select|choose|please|--|\u2014)/.test(txt)) return false;\n    }\n    return true;\n  }\n  if (el instanceof HTMLInputElement) {\n    if (el.type === 'checkbox' || el.type === 'radio') return !!el.checked;\n    return !!el.value?.trim();\n  }\n  if (el instanceof HTMLTextAreaElement) return !!el.value?.trim();\n  return false;\n}\n\nfunction getFieldLabel(el: HTMLElement): string {\n  const ariaLabel = el.getAttribute('aria-label');\n  if (ariaLabel?.trim()) return ariaLabel.trim();\n\n  if (el.id) {\n    const lbl = el.ownerDocument.querySelector(`label[for=\"${CSS.escape(el.id)}\"]`);\n    if (lbl?.textContent?.trim()) return lbl.textContent.trim();\n  }\n\n  if ((el as HTMLInputElement).placeholder?.trim()) return (el as HTMLInputElement).placeholder.trim();\n\n  const container = el.closest('.form-group,.field,.question,[class*=\"Field\"],[class*=\"Question\"],[class*=\"form-row\"],li,.form-item,.ant-form-item,.ant-row');\n  if (container) {\n    const lbl = container.querySelector('label,[class*=\"label\"],[class*=\"Label\"]');\n    if (lbl && lbl !== el && lbl.textContent?.trim()) return lbl.textContent.trim();\n  }\n\n  const name = el.getAttribute('name');\n  if (name) return name.replace(/[_\\-]/g, ' ');\n\n  return '';\n}\n", "import type { ExtMessage, ExtResponse } from '../types/index';\nimport * as store from '../savedResponses/storage';\nimport { findMatches } from '../savedResponses/matcher';\nimport { findDuplicates } from '../utils/fuzzy';\nimport * as queue from '../jobQueue/storage';\nimport * as settings from '../settings/storage';\nimport * as autoApply from '../autoApply/engine';\nimport * as scraper from '../autoApply/scraper';\nimport * as answerBankModule from '../answerBank/index';\n\nchrome.runtime.onMessage.addListener((msg: ExtMessage, _sender, sendResponse) => {\n  handleMessage(msg).then(sendResponse).catch((e) => sendResponse({ ok: false, error: String(e) }));\n  return true; // async\n});\n\nasync function handleMessage(msg: ExtMessage): Promise<ExtResponse> {\n  const p = msg.payload as any;\n\n  switch (msg.type) {\n    // \u2500\u2500\u2500 Libraries \u2500\u2500\u2500\n    case 'GET_LIBRARIES':\n      return { ok: true, data: await store.getLibraries() };\n    case 'GET_ACTIVE_LIBRARY':\n      return { ok: true, data: await store.getActiveLibrary() };\n    case 'SET_ACTIVE_LIBRARY':\n      await store.setActiveLibrary(p.id);\n      return { ok: true };\n    case 'CREATE_LIBRARY':\n      return { ok: true, data: await store.createLibrary(p.name) };\n    case 'DELETE_LIBRARY':\n      return { ok: true, data: await store.deleteLibrary(p.id) };\n\n    // \u2500\u2500\u2500 Domain Mappings \u2500\u2500\u2500\n    case 'GET_DOMAIN_MAPPINGS':\n      return { ok: true, data: await store.getDomainMappings() };\n    case 'SET_DOMAIN_MAPPING':\n      await store.setDomainMapping(p.domain, p.libraryId);\n      return { ok: true };\n    case 'REMOVE_DOMAIN_MAPPING':\n      await store.removeDomainMapping(p.domain);\n      return { ok: true };\n\n    // \u2500\u2500\u2500 Responses CRUD \u2500\u2500\u2500\n    case 'GET_RESPONSES':\n      return { ok: true, data: await store.getResponses(p?.libraryId) };\n    case 'SAVE_RESPONSE':\n      return { ok: true, data: await store.saveResponse(p.response, p.libraryId) };\n    case 'DELETE_RESPONSE':\n      await store.deleteResponse(p.id, p.libraryId);\n      return { ok: true };\n    case 'DELETE_RESPONSES':\n      await store.deleteResponses(p.ids, p.libraryId);\n      return { ok: true };\n    case 'SEARCH_RESPONSES':\n      return { ok: true, data: await store.searchResponses(p.query, p.libraryId) };\n    case 'BULK_TAG':\n      await store.bulkTag(p.ids, p.tags, p.libraryId);\n      return { ok: true };\n    case 'MERGE_RESPONSES':\n      await store.mergeResponses(p.keepId, p.mergeId, p.libraryId);\n      return { ok: true };\n    case 'RECORD_USAGE':\n      await store.recordUsage(p.id, p.libraryId);\n      return { ok: true };\n\n    // \u2500\u2500\u2500 Import / Export \u2500\u2500\u2500\n    case 'IMPORT_RESPONSES':\n      return { ok: true, data: await store.importResponses(p.data, p.libraryId, p.mode) };\n    case 'EXPORT_RESPONSES':\n      return { ok: true, data: await store.exportResponses(p?.libraryId) };\n    case 'EXPORT_ENCRYPTED':\n      return { ok: true, data: await store.exportEncrypted(p.passphrase, p.libraryId) };\n    case 'IMPORT_ENCRYPTED':\n      return { ok: true, data: await store.importEncrypted(p.data, p.passphrase, p.libraryId, p.mode) };\n\n    // \u2500\u2500\u2500 Suggestions (for content script) \u2500\u2500\u2500\n    case 'GET_SUGGESTIONS': {\n      const lib = p.domain\n        ? await store.getLibraryForDomain(p.domain)\n        : await store.getActiveLibrary();\n      const matches = findMatches(p.query, lib.responses, { domain: p.domain, atsType: p.atsType, maxResults: 3 });\n      return { ok: true, data: matches };\n    }\n\n    // \u2500\u2500\u2500 Job Queue \u2500\u2500\u2500\n    case 'GET_JOB_QUEUE':\n      return { ok: true, data: await queue.getItems() };\n    case 'ADD_JOB_URLS':\n      return { ok: true, data: await queue.addUrls(p.urls) };\n    case 'IMPORT_JOB_CSV': {\n      const stats = await queue.importCSVJobs(p.csv);\n      return { ok: true, data: stats };\n    }\n    case 'UPDATE_JOB_STATUS':\n      await queue.updateStatus(p.id, p.status, p.reason);\n      return { ok: true };\n    case 'CLEAR_JOB_QUEUE':\n      await queue.clearQueue();\n      return { ok: true };\n    case 'OPEN_JOB_TAB':\n      await chrome.tabs.create({ url: p.url, active: true });\n      await queue.updateStatus(p.id, 'opened');\n      return { ok: true };\n    case 'REMOVE_JOB':\n      await queue.removeItem(p.id);\n      return { ok: true };\n    case 'RETRY_FAILED_JOBS': {\n      const retried = await queue.retryFailed();\n      return { ok: true, data: retried };\n    }\n    case 'GET_IMPORT_STATS':\n      return { ok: true, data: await queue.getImportStats() };\n    case 'EXPORT_JOB_RESULTS': {\n      const csv = await queue.exportQueue();\n      return { ok: true, data: csv };\n    }\n\n    // \u2500\u2500\u2500 Auto-Apply Pipeline \u2500\u2500\u2500\n    case 'START_AUTO_APPLY':\n      autoApply.startAutoApply(p?.source || 'all');\n      return { ok: true };\n    case 'STOP_AUTO_APPLY':\n      autoApply.stopAutoApply();\n      return { ok: true };\n    case 'PAUSE_AUTO_APPLY':\n      autoApply.pauseAutoApply();\n      return { ok: true };\n    case 'RESUME_AUTO_APPLY':\n      autoApply.resumeAutoApply();\n      return { ok: true };\n    case 'GET_AUTO_APPLY_STATUS':\n      return { ok: true, data: autoApply.getStatus() };\n\n    // \u2500\u2500\u2500 Settings \u2500\u2500\u2500\n    case 'GET_SETTINGS':\n      return { ok: true, data: await settings.loadSettings() };\n    case 'SAVE_SETTINGS':\n      await settings.saveSettings(p);\n      return { ok: true };\n\n    // \u2500\u2500\u2500 Applications Account \u2500\u2500\u2500\n    case 'SAVE_APP_ACCOUNT':\n      await settings.saveAppAccount(p.email, p.password, p.passphrase);\n      return { ok: true };\n    case 'GET_APP_ACCOUNT': {\n      const account = await settings.getAppAccount(p.passphrase);\n      if (account) return { ok: true, data: { email: account.email } }; // Never return password to UI\n      return { ok: false, error: 'Invalid passphrase or no account saved' };\n    }\n    case 'CLEAR_APP_ACCOUNT':\n      await settings.clearAppAccount();\n      return { ok: true };\n\n    // \u2500\u2500\u2500 Credits \u2500\u2500\u2500\n    case 'GET_CREDITS':\n    case 'CHECK_CREDITS':\n      return { ok: true, data: await settings.checkCredits() };\n\n    // \u2500\u2500\u2500 Scraper \u2500\u2500\u2500\n    case 'START_SCRAPER':\n      await scraper.startScraper();\n      return { ok: true };\n    case 'STOP_SCRAPER':\n      scraper.stopScraper();\n      return { ok: true };\n    case 'GET_SCRAPED_JOBS': {\n      const jobs = await scraper.getRankedJobs(p?.targetCount);\n      return { ok: true, data: jobs };\n    }\n\n    // \u2500\u2500\u2500 Autofill (forwarded to content script via tabs) \u2500\u2500\u2500\n    case 'START_AUTOFILL': {\n      const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });\n      if (tab?.id) {\n        await chrome.tabs.sendMessage(tab.id, { type: 'START_AUTOFILL', payload: p });\n      }\n      return { ok: true };\n    }\n    case 'STOP_AUTOFILL': {\n      const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });\n      if (tab?.id) {\n        await chrome.tabs.sendMessage(tab.id, { type: 'STOP_AUTOFILL' });\n      }\n      return { ok: true };\n    }\n    case 'DETECT_ATS': {\n      const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });\n      if (tab?.id) {\n        const r = await chrome.tabs.sendMessage(tab.id, { type: 'DETECT_ATS' });\n        return { ok: true, data: r };\n      }\n      return { ok: false, error: 'No active tab' };\n    }\n    case 'AUTO_DETECT_FILL': {\n      const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });\n      if (tab?.id) {\n        await chrome.tabs.sendMessage(tab.id, { type: 'AUTO_DETECT_FILL' });\n      }\n      return { ok: true };\n    }\n    case 'PAGE_AUTOFILL_COMPLETE':\n      // Content script reports completion - forwarded to auto-apply engine\n      return { ok: true };\n\n    // \u2500\u2500\u2500 One-click add current page to queue \u2500\u2500\u2500\n    case 'ADD_CURRENT_PAGE_TO_QUEUE': {\n      const url = p?.url;\n      if (!url) return { ok: false, error: 'No URL provided' };\n      // Check for duplicates\n      const existing = await queue.getItems();\n      const normalized = queue.normalizeUrl(url);\n      const isDuplicate = existing.some((i) => queue.normalizeUrl(i.url) === normalized);\n      if (isDuplicate) return { ok: false, error: 'Already in queue' };\n      const added = await queue.addUrls([{\n        url,\n        company: p.company || undefined,\n        role: p.role || undefined,\n      }]);\n      // Override source to 'one_click' by updating the just-added item\n      if (added > 0 && p.source === 'one_click') {\n        const items = await queue.getItems();\n        const item = items.find((i) => queue.normalizeUrl(i.url) === normalized);\n        if (item) {\n          item.source = 'one_click';\n          // Save directly since addUrls set it as 'manual'\n          const state = await queue.loadQueue();\n          const stateItem = state.items.find((i) => i.id === item.id);\n          if (stateItem) stateItem.source = 'one_click';\n          await chrome.storage.local.set({ ua_job_queue: state });\n        }\n      }\n      return { ok: true, data: { added } };\n    }\n\n    // \u2500\u2500\u2500 AI Tailoring \u2500\u2500\u2500\n    case 'TAILOR_RESPONSE':\n      return { ok: true }; // Tailoring is handled in content script\n    case 'GET_TAILORING_STATUS': {\n      const s = await settings.loadSettings();\n      return { ok: true, data: { enabled: s.tailoring.enabled, intensity: s.tailoring.intensity } };\n    }\n\n    // \u2500\u2500\u2500 Answer Bank & Profile \u2500\u2500\u2500\n    case 'GET_ANSWER_BANK':\n      return { ok: true, data: await answerBankModule.loadAnswerBank() };\n    case 'SAVE_ANSWER':\n      await answerBankModule.learnAnswer(p.label, p.value);\n      return { ok: true };\n    case 'CLEAR_ANSWER_BANK':\n      await chrome.storage.local.remove('ua_answer_bank');\n      return { ok: true };\n    case 'GET_PROFILE':\n      return { ok: true, data: await answerBankModule.loadProfile() };\n    case 'SAVE_PROFILE':\n      await answerBankModule.saveProfile(p);\n      return { ok: true };\n\n    default:\n      return { ok: false, error: `Unknown message: ${msg.type}` };\n  }\n}\n\n// On install, initialize storage\nchrome.runtime.onInstalled?.addListener(async () => {\n  const state = await store.loadState();\n  if (!state.libraries.length) {\n    await store.saveState({\n      libraries: [{\n        id: 'default',\n        name: 'Default',\n        responses: [],\n        createdAt: new Date().toISOString(),\n        updatedAt: new Date().toISOString(),\n      }],\n      activeLibraryId: 'default',\n      domainMappings: {},\n    });\n  }\n  // Initialize settings with defaults\n  await settings.loadSettings();\n});\n\n// Auto-detect ATS on tab updates and trigger autofill if enabled\n// Now works universally on ALL pages (not just domain allowlist) when universal mode is on\nchrome.tabs.onUpdated.addListener(async (tabId, changeInfo, tab) => {\n  if (changeInfo.status !== 'complete' || !tab.url) return;\n  // Skip chrome:// and extension pages\n  if (tab.url.startsWith('chrome://') || tab.url.startsWith('chrome-extension://')) return;\n\n  try {\n    const s = await settings.loadSettings();\n    if (!s.autoDetectAndFill) return;\n\n    const url = tab.url;\n\n    // If universal form detection is enabled, try on ALL pages\n    // Otherwise, only on domain-allowlisted pages\n    if (!s.universalFormDetection) {\n      const isSupported = s.autoApply.domainAllowlist.some((d) => url.includes(d));\n      if (!isSupported) return;\n    }\n\n    // Send auto-detect-and-fill to the content script\n    try {\n      await chrome.tabs.sendMessage(tabId, { type: 'AUTO_DETECT_FILL' });\n    } catch {\n      // Content script not yet loaded, ignore\n    }\n  } catch {\n    // Settings not yet initialized, ignore\n  }\n});\n"],
